27	export async function sendRecallChatMessage(args: {
28	  botId: string;
29	  message: string;
30	}): Promise<void> {
31	  let res: Response;
32	  try {
33	    res = await fetch(`${recallBaseUrl()}/api/v1/bot/${args.botId}/send_chat_message/`, {
34	      method: 'POST',
35	      headers: {
36	        Authorization: recallApiKey(),
37	        accept: 'application/json',
38	        'content-type': 'application/json',
39	      },
40	      body: JSON.stringify({
41	        to: 'everyone',
42	        message: args.message.slice(0, 4096),
43	      }),
44	      signal: AbortSignal.timeout(15_000),
45	    });
46	  } catch (err) {
47	    // Network failure or timeout (AbortError) — treat as transient.
48	    throw new RecallTransientSendError(
49	      `Recall send_chat_message network failure: ${err instanceof Error ? err.message : String(err)}`,
50	    );
51	  }
52	  if (!res.ok) {
53	    const detail = (await res.text()).slice(0, 500);
54	    const message = `Recall send_chat_message failed (${res.status}): ${detail}`;
55	    // 429 (rate limited) and 5xx (server) are transient; 4xx (other) are not.
56	    if (res.status === 429 || res.status >= 500) {
57	      throw new RecallTransientSendError(message, res.status);
58	    }
59	    throw new Error(message);
