1	// POST/GET /api/teams/notifications
2	//
3	// The "always-on listener" for Microsoft Graph change notifications about
4	// Teams ad-hoc call transcripts (subscription resource:
5	// communications/adhocCalls/getAllTranscripts).
6	//
7	// This endpoint MUST be deployed and publicly reachable BEFORE the subscription
8	// can be created — Graph validates it synchronously at subscription-create time
9	// by calling it with a ?validationToken=... that we have to echo back within
10	// 10 seconds. See apps/web/lib/microsoft-graph.ts createAdhocTranscriptSubscription.
11	//
12	// Responsibilities (kept deliberately fast — Graph disables subscriptions whose
13	// endpoint is slow or erroring):
14	//   1. Answer the validation handshake (echo validationToken as text/plain).
15	//   2. Verify the shared `clientState` secret on every real notification.
16	//   3. Decrypt the rich-notification payload to learn which transcript fired.
17	//   4. Hand off to the `teams-transcript-ingestion` worker — never fetch the
18	//      transcript or run extraction inline here.
19	//   5. Handle lifecycle events by asking the subscription manager to reauthorize.
20	//
21	// Both notificationUrl and lifecycleNotificationUrl on the subscription point
22	// here; we branch on the payload shape.
23	
24	import { NextResponse, type NextRequest } from 'next/server';
25	import { triggerTask } from '@/lib/trigger';
26	import {
27	  decryptResourceData,
28	  type GraphEncryptedContent,
29	} from '@/lib/graph-notification-crypto';
30	
31	export const dynamic = 'force-dynamic';
32	export const runtime = 'nodejs'; // node:crypto + Buffer needed for decryption
33	
34	interface GraphNotification {
35	  subscriptionId?: string;
36	  clientState?: string;
37	  changeType?: string;
38	  resource?: string;
39	  resourceData?: { id?: string; '@odata.id'?: string } | null;
40	  encryptedContent?: GraphEncryptedContent;
41	  lifecycleEvent?: 'reauthorizationRequired' | 'subscriptionRemoved' | 'missed';
42	}
43	
44	interface GraphNotificationEnvelope {
45	  value?: GraphNotification[];
46	}
47	
48	/** Decrypted callTranscript shape — only the fields we use. */
49	interface DecryptedTranscript {
50	  transcriptContentUrl?: string;
51	  meetingId?: string;
52	  callId?: string;
53	  meetingOrganizer?: unknown;
54	  createdDateTime?: string;
55	}
