57	/**
58	 * If this request is Graph's validation handshake, return the text/plain echo
59	 * response. Otherwise return null and let the caller process notifications.
60	 */
61	function handleValidation(req: NextRequest): NextResponse | null {
62	  const token = req.nextUrl.searchParams.get('validationToken');
63	  if (token === null) return null;
64	  return new NextResponse(token, {
65	    status: 200,
66	    headers: { 'content-type': 'text/plain' },
67	  });
68	}
69	
70	export function GET(req: NextRequest): NextResponse {
71	  return handleValidation(req) ?? NextResponse.json({ ok: true });
72	}
73	
74	export async function POST(req: NextRequest): Promise<NextResponse> {
75	  // 1. Validation handshake (fires on subscription create + renewal).
76	  const validation = handleValidation(req);
77	  if (validation) return validation;
78	
79	  // 2. Parse the envelope.
80	  let body: GraphNotificationEnvelope;
81	  try {
82	    body = (await req.json()) as GraphNotificationEnvelope;
83	  } catch {
84	    return NextResponse.json({ error: 'Bad JSON' }, { status: 400 });
85	  }
86	  const notifications = body.value ?? [];
87	
88	  const expectedClientState = process.env.TEAMS_WEBHOOK_CLIENT_STATE;
89	  const privateKeyPem = process.env.TEAMS_NOTIFICATION_PRIVATE_KEY;
90	
91	  for (const n of notifications) {
92	    // Lifecycle events (reauthorizationRequired / subscriptionRemoved / missed):
93	    // the subscription needs attention — let the manager handle it.
94	    if (n.lifecycleEvent) {
95	      void triggerTask('teams-subscription-manager', {
96	        reason: n.lifecycleEvent,
97	        subscriptionId: n.subscriptionId ?? null,
98	      });
99	      continue;
100	    }

