24	export function verifyRecallRequest(args: {
25	  secret: string;
26	  headers: Headers;
27	  payload: string | null;
28	}): void {
29	  const { secret, headers, payload } = args;
30	  const msgId = headers.get('webhook-id') ?? headers.get('svix-id');
31	  const msgTimestamp = headers.get('webhook-timestamp') ?? headers.get('svix-timestamp');
32	  const msgSignature = headers.get('webhook-signature') ?? headers.get('svix-signature');
33	  if (!secret || !secret.startsWith('whsec_')) {
34	    throw new Error('Recall verification secret is missing or invalid');
35	  }
36	  if (!msgId || !msgTimestamp || !msgSignature) {
37	    throw new Error('Missing Recall verification headers');
38	  }
39	
40	  const key = Buffer.from(secret.slice('whsec_'.length), 'base64');
41	  const toSign = `${msgId}.${msgTimestamp}.${payload ?? ''}`;
42	  const expectedSig = crypto.createHmac('sha256', key).update(toSign).digest('base64');
43	  const expectedBytes = Buffer.from(expectedSig, 'base64');
