45	  for (const versionedSig of msgSignature.split(' ')) {
46	    const [version, signature] = versionedSig.split(',');
47	    if (version !== 'v1' || !signature) continue;
48	    const actualBytes = Buffer.from(signature, 'base64');
49	    if (
50	      expectedBytes.length === actualBytes.length &&
51	      crypto.timingSafeEqual(new Uint8Array(expectedBytes), new Uint8Array(actualBytes))
52	    ) {
53	      return;
54	    }
55	  }
56	  throw new Error('No matching Recall signature found');
57	}
